import { register_client } from "std/oauth/dynamic_registration"

fn register(store, metadata) {
  let registered = register_client(store, metadata)
  emit_audit("oauth.dynreg.audit", "client_registered", {client_id: registered.client_id, client_secret: registered.client_secret})
  return registered.client_id
}

import { register_client } from "std/oauth/dynamic_registration"

fn register(store, metadata) {
  let registered = register_client(store, metadata)
  emit_audit("oauth.dynreg.audit", "client_registered", {client_id: registered.client_id, has_client_secret: registered.client_secret != nil})
  return registered.client_id
}
